_k = d_model // n_heads\n        \n        self.w_q = nn.Linear(d_model, d_model)\n        self.w_k = nn.Linear(d_model, d_model)\n        self.w_v = nn.Linear(d_model, d_model)\n        self.w_o = nn.Linear(d_model, d_model)\n        \n    def scaled_dot_product_attention(self, Q, K, V, mask=None):\n        scores = torch.matmul(Q, K.transpose(-2, -1)) / math.sqrt(self.d_k)\n        \n        if mask is not None:\n            scores = scores.masked_fill(mask == 0, -1e9)\n            \n        attention_weights = F.softmax(scores, dim=-1)\n        output = torch.matmul(attention_weights, V)\n        return output, attention_weights\n    \n    def forward(self, query, key, value, mask=None):\n        batch_size = query.size(0)\n        \n        # Linear projections\n        Q = self.w_q(query).view(batch_size, -1, self.n_heads, self.d_k).transpose(1, 2)\n        K = self.w_k(key).view(batch_size, -1, self.n_heads, self.d_k).transpose(1, 2)\n        V = self.w_v(value).view(batch_size, -1, self.n_heads, self.d_k).transpose(1, 2)\n        \n        # Attention\n        attn_output, attn_weights = self.scaled_dot_product_attention(Q, K, V, mask)\n        \n        # Concatenate heads\n        attn_output = attn_output.transpose(1, 2).contiguous().view(\n            batch_size, -1, self.d_model)\n        \n        return self.w_o(attn_output)"})]})]}),(0,lo.jsxs)(Hk,{children:[(0,lo.jsx)(Vk,{children:"Key Interview Topics"}),(0,lo.jsxs)(Xk,{children:[(0,lo.jsxs)("li",{children:[(0,lo.jsx)(rS,{size:16}),(0,lo.jsx)("strong",{children:"Attention vs. RNN/CNN:"})," Explain why attention enables parallelization and better long-range dependencies"]}),(0,lo.jsxs)("li",{children:[(0,lo.jsx)(rS,{size:16}),(0,lo.jsx)("strong",{children:"Computational Complexity:"})," O(n\xb2d) for attention vs O(nd\xb2) for RNNs, where n is sequence length"]}),(0,lo.jsxs)("li",{children:[(0,lo.jsx)(rS,{size:16}),(0,lo.jsx)("strong",{children:"Positional Encoding:"})," Why sinusoidal functions work